using sv_17dcc158e7764d5bad6975fe548799e6.Models;

namespace sv_17dcc158e7764d5bad6975fe548799e6.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato sauce, mozzarella, and fresh basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino cheese.", 20),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 40),
            new(4, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked to creamy perfection.", 35),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts and vegetables.", 30),
            new(6, "Mapo Tofu", "Silken tofu in a fiery Sichuan peppercorn sauce.", 20),
            new(7, "Xiaolongbao", "Steamed soup dumplings filled with pork and rich broth.", 60),
            new(8, "Char Siu", "Cantonese-style barbecue pork with a sweet glaze.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Butter Chicken", "Tender chicken in a creamy tomato-based curry sauce.", 45),
            new(10, "Biryani", "Fragrant basmati rice layered with spiced meat and herbs.", 60),
            new(11, "Samosa", "Crispy pastry filled with spiced potatoes and peas.", 35),
            new(12, "Palak Paneer", "Cottage cheese cubes in a smooth spinach gravy.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_17dcc158e7764d5bad6975fe548799e6.Models
@using sv_17dcc158e7764d5bad6975fe548799e6.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <h3>Recipes</h3>
    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IReadOnlyList<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Array.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when CuisineId changes, not when sort changes.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // Guard against late completions after disposal.
            if (token.IsCancellationRequested) return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Expected when navigating away or switching cuisine — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

